struct Point{T<:Real}
    x::T
    y::T
end

dist(p::Point{T}) where {T} = sqrt(p.x^2 + p.y^2)

pi_ = Point(3.0, 4.0)   # Point{Float64}
qi = Point(3, 4)        # Point{Int64}

println(typeof(pi_))    # Point{Float64}
println(dist(pi_))      # 5.0
println(Vector{Int} == Array{Int,1})  # true

function sumsq(v)
    s = zero(eltype(v))
    for x in v
        s += x^2
    end
    return s
end

@code_warntype sumsq([1.0, 2.0, 3.0])
# Body::Float64  -> good, fully inferred

# Lower-level inspection
@code_llvm sumsq([1.0, 2.0])
@code_native sumsq([1.0, 2.0])

macro sayhello(name)
    return :( println("Hello, ", $name) )
end

@sayhello "Julia"          # expands to println(...)

# A timing-style macro
macro twice(ex)
    quote
        $(esc(ex))
        $(esc(ex))
    end
end

@twice println("run")      # prints twice

@macroexpand @sayhello "x" # inspect generated code

function work(n)
    s = 0.0
    for i in 1:n
        s += sqrt(i)
    end
    s
end

@time work(10^6)   # first run: includes compilation
@time work(10^6)   # second run: real timing + allocs

# Better: BenchmarkTools
using BenchmarkTools
@btime work(10^6)
@btime work($(10^6))  # interpolate to avoid globals
